import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10;

        // Ensure that input length does not exceed buffer size
        if (input.length() > bufferSize) {
            System.out.println("Input length exceeds buffer size. Truncating input...");
            input = input.substring(0, bufferSize);
        }

        char[] buffer = new char[bufferSize];

        // Copy input to buffer safely
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

